UPDATE spells SET summary = 'Lightning springs from hand to touch. Melee spell attack, advantage if target wearing metal armor. Hit: {@damage 1d8} lightning damage, target can''t take reactions until start of next turn. Damage increases by {@damage 1d8} at 5th, 11th, 17th level.' WHERE slug = 'shocking-grasp';
UPDATE spells SET summary = 'Vine whip lashes creature in range. Melee spell attack. Hit: {@damage 1d6} piercing, pull Large or smaller creature 10 feet closer. Damage increases by {@damage 1d6} at 5th, 11th, 17th level.' WHERE slug = 'thorn-whip';
UPDATE spells SET summary = 'Point at creature within range. Target makes Wisdom save or takes {@damage 1d8} necrotic damage. If missing any HP, takes {@damage 1d12} instead. Damage increases by one die at 5th, 11th, 17th level.' WHERE slug = 'toll-the-dead';
UPDATE spells SET summary = 'Unleash insults with enchantments at creature in range. Target hears you, makes Wisdom save or takes {@damage 1d4} psychic damage and disadvantage on next attack before end of next turn. Damage increases by {@damage 1d4} at 5th, 11th, 17th level.' WHERE slug = 'vicious-mockery';
UPDATE spells SET summary = 'Capture incoming energy damage. Resistance to triggering type until start of next turn. First melee hit next turn adds {@damage 1d6} extra damage of triggering type. Extra damage increases by {@damage 1d6} per slot level above 1st.' WHERE slug = 'absorb-elements';
UPDATE spells SET summary = 'Convince beast you mean no harm. Choose beast within range that sees/hears you. Intelligence 4+ spell fails. Beast makes Wisdom save or is {@condition charmed} until spell ends. Harms end spell. Affects one additional beast per slot level above 1st.' WHERE slug = 'animal-friendship';
UPDATE spells SET summary = 'Spectral frost surrounds you. Gain 5 temporary HP. Melee attacker takes 5 cold damage. Temporary HP and cold damage increase by 5 per slot level above 1st.' WHERE slug = 'armor-of-agathys';
UPDATE spells SET summary = 'Invoke Hadar''s power. Tendrils erupt, all creatures within 10 feet make Strength save. Failed: {@damage 2d6} necrotic, can''t take reactions. Success: half damage. Damage increases by {@damage 1d6} per slot level above 1st.' WHERE slug = 'arms-of-hadar';
UPDATE spells SET summary = 'Target up to 3 creatures within range. Charisma saves. Failed: when target attacks or saves before spell ends, roll {@dice d4} and subtract from attack or save roll. Target one additional creature per slot level above 1st.' WHERE slug = 'bane';
UPDATE spells SET summary = 'Touch friendly or {@condition charmed} beast. Fails if Intelligence 4+. Telepathic link while in line of sight. Beast understands messages, sends emotions back. Linked beast gets advantage on attacks within 5 feet of you against creatures you can see.' WHERE slug = 'beast-bond';
UPDATE spells SET summary = 'Bless up to 3 creatures within range. When target attacks or saves before spell ends, roll {@dice d4} and add to attack or save. Affects one additional creature per slot level above 1st.' WHERE slug = 'bless';
UPDATE spells SET summary = '15-foot cone of flames from hands. Creatures make Dexterity save. Failed: {@damage 3d6} fire. Success: half damage. Ignites unattended flammable objects. Damage increases by {@damage 1d6} per slot level above 1st.' WHERE slug = 'burning-hands';
UPDATE spells SET summary = 'Choose object 1-5 lbs within range, not worn/carried. Object flies 90 feet, stops if hits solid surface or creature. Creature hit makes Dexterity save. Failed: object strikes, deals {@damage 3d8} bludgeoning. Max weight +5 lbs and damage +{@damage 1d8} per slot level above 1st.' WHERE slug = 'catapult';
UPDATE spells SET summary = 'Awaken mortality sense in creature within range. Construct/undead immune. Wisdom save or {@condition frightened} until spell ends. Can repeat save at end of each turn. Target one additional creature per slot level above 1st (30 feet apart).' WHERE slug = 'cause-fear';
UPDATE spells SET summary = 'Attempt charm humanoid within range. Advantage on save if fighting you/companions. Failed: {@condition charmed}} until spell ends or harm done. Knows it was charmed when spell ends. Target one additional creature per slot level above 1st (30 feet apart).' WHERE slug = 'charm-person';
UPDATE spells SET summary = 'Hurl 4-inch energy sphere at creature within range. Choose acid, cold, fire, lightning, poison, or thunder. Ranged spell attack. Hit: {@damage 3d8} damage of chosen type. Damage increases by {@damage 1d8} per slot level above 1st.' WHERE slug = 'chromatic-orb';
UPDATE spells SET summary = 'Touch creature. Regains {@dice 1d8} + ability modifier HP. No effect on undead/constructs. Healing increases by {@dice 1d8} per slot level above 1st.' WHERE slug = 'cure-wounds';
UPDATE spells SET summary = 'Ground tremor within range. Creatures make Dexterity save. Failed: {@damage 1d6} bludgeoning, knocked {@condition prone}. Loose earth/stone becomes difficult terrain. Damage increases by {@damage 1d6} per slot level above 1st.' WHERE slug = 'earth-tremor';
UPDATE spells SET summary = 'Gain {@dice 1d4 + 4} temporary HP for duration. Gain 5 additional temporary HP per slot level above 1st.' WHERE slug = 'false-life';
UPDATE spells SET summary = '20-foot-radius fog sphere centered within range. Area heavily obscured, spreads around corners. Wind 10+ mph disperses. Radius increases 20 feet per slot level above 1st.' WHERE slug = 'fog-cloud';
UPDATE spells SET summary = 'Flash of light to creature within range. Ranged spell attack. Hit: {@damage 4d6} radiant damage, next attack roll against target has advantage until end of your next turn. Damage increases by {@damage 1d6} per slot level above 1st.' WHERE slug = 'guiding-bolt';
UPDATE spells SET summary = 'Next ranged attack before spell ends triggers rain of thorns. Target and creatures within 5 feet make Dexterity save. Failed: {@damage 1d10} piercing. Success: half damage. Damage increases by {@damage 1d10} per slot level above 1st (max {@damage 6d10}).' WHERE slug = 'hail-of-thorns';
UPDATE spells SET summary = 'Creature within range regains {@dice 1d4} + ability modifier HP. No effect on undead/constructs. Healing increases by {@dice 1d4} per slot level above 1st.' WHERE slug = 'healing-word';
UPDATE spells SET summary = 'Creature that damaged you surrounded by hellish flames. Dexterity save or takes {@damage 2d10} fire. Success: half damage. Damage increases by {@damage 1d10} per slot level above 1st.' WHERE slug = 'hellish-rebuke';
UPDATE spells SET summary = 'Willing creature touched imbued with bravery. Immune to {@condition frightened}. Gains temporary HP equal to ability modifier at start of each turn. Loses remaining temporary HP when spell ends. One additional creature per slot level above 1st.' WHERE slug = 'heroism';
UPDATE spells SET summary = 'Mystically mark creature within range as quarry. Deal extra {@damage 1d6} damage on weapon hits. Advantage on Perception/Survival checks to find target. When target reaches 0 HP, mark new creature with bonus action. Concentration 8 hours (3-4 slot), 24 hours (5+ slot).' WHERE slug = 'hunter''s-mark';
UPDATE spells SET summary = 'Create ice shard, fling at creature within range. Ranged spell attack. Hit: {@damage 1d10} piercing. Hit or miss: explosion, target and creatures within 5 feet make Dexterity save or take {@damage 2d6} cold. Cold damage increases by {@damage 1d6} per slot level above 1st.' WHERE slug = 'ice-knife';
UPDATE spells SET summary = 'Melee spell attack against creature within reach. Hit: {@damage 3d10} necrotic damage. Damage increases by {@damage 1d10} per slot level above 1st.' WHERE slug = 'inflict-wounds';
UPDATE spells SET summary = 'Touch creature. Target''s speed increases 10 feet until spell ends. Target one additional creature per slot level above 1st.' WHERE slug = 'longstrider';
UPDATE spells SET summary = 'Create 3 glowing darts of magical force. Each hits creature you choose within range. Dart deals {@damage 1d4 + 1} force damage. Strike simultaneously, target one or several. One more dart per slot level above 1st.' WHERE slug = 'magic-missile';
